import React, { useState, useEffect } from 'react';
import { analyticsAPI } from '../services/api';
import { 
  TrendingUp, 
  TrendingDown, 
  DollarSign, 
  Package, 
  ShoppingCart, 
  Users, 
  Activity,
  BarChart3,
  PieChart,
  Calendar,
  ArrowUp,
  ArrowDown
} from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, PieChart as RePieChart, Pie, Cell } from 'recharts';
import toast from 'react-hot-toast';

const Analytics = () => {
  const [pricingData, setPricingData] = useState(null);
  const [orderData, setOrderData] = useState(null);
  const [competitorData, setCompetitorData] = useState([]);
  const [dashboardData, setDashboardData] = useState(null);
  const [timeframe, setTimeframe] = useState('7d');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchAnalyticsData();
  }, [timeframe]);

  const fetchAnalyticsData = async () => {
    try {
      setLoading(true);

      const [pricingResponse, orderResponse, competitorResponse, dashboardResponse] = await Promise.all([
        analyticsAPI.getPricing(timeframe),
        analyticsAPI.getOrders(timeframe),
        analyticsAPI.getCompetitorPrices(),
        analyticsAPI.getDashboard()
      ]);

      setPricingData(pricingResponse.data);
      setOrderData(orderResponse.data);
      setCompetitorData(competitorResponse.data);
      setDashboardData(dashboardResponse.data);
    } catch (error) {
      console.error('Error fetching analytics data:', error);
      toast.error('Failed to load analytics data');
    } finally {
      setLoading(false);
    }
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(price);
  };

  const formatNumber = (num) => {
    if (num >= 1000000) {
      return (num / 1000000).toFixed(1) + 'M';
    } else if (num >= 1000) {
      return (num / 1000).toFixed(1) + 'K';
    }
    return num.toString();
  };

  const COLORS = ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Analytics Dashboard</h1>
          <p className="text-gray-600 mt-1">Monitor your business performance and pricing trends</p>
        </div>

        {/* Timeframe Selector */}
        <div className="mt-4 md:mt-0">
          <div className="flex items-center space-x-2">
            <Calendar className="h-4 w-4 text-gray-400" />
            <select
              value={timeframe}
              onChange={(e) => setTimeframe(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
            >
              <option value="1d">Last 24 Hours</option>
              <option value="7d">Last 7 Days</option>
              <option value="30d">Last 30 Days</option>
            </select>
          </div>
        </div>
      </div>

      {/* Dashboard Stats */}
      {dashboardData && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-2">
                <Package className="h-5 w-5 text-primary-600" />
                <span className="text-sm font-medium text-gray-600">Active Products</span>
              </div>
            </div>
            <p className="text-2xl font-bold text-gray-900">
              {dashboardData.active_products?.total_products || 0}
            </p>
            <p className="text-sm text-gray-500 mt-1">
              Avg price: {formatPrice(dashboardData.active_products?.avg_price || 0)}
            </p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-2">
                <DollarSign className="h-5 w-5 text-success-600" />
                <span className="text-sm font-medium text-gray-600">Today's Revenue</span>
              </div>
            </div>
            <p className="text-2xl font-bold text-gray-900">
              {formatPrice(dashboardData.today_orders?.total_revenue || 0)}
            </p>
            <p className="text-sm text-gray-500 mt-1">
              {dashboardData.today_orders?.total_orders || 0} orders
            </p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-2">
                <Activity className="h-5 w-5 text-warning-600" />
                <span className="text-sm font-medium text-gray-600">Today's Views</span>
              </div>
            </div>
            <p className="text-2xl font-bold text-gray-900">
              {formatNumber(dashboardData.today_metrics?.total_views || 0)}
            </p>
            <p className="text-sm text-gray-500 mt-1">
              {dashboardData.today_metrics?.unique_viewers || 0} unique visitors
            </p>
          </div>

          <div className="bg-white p-6 rounded-lg shadow-soft">
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center space-x-2">
                <TrendingUp className="h-5 w-5 text-danger-600" />
                <span className="text-sm font-medium text-gray-600">Price Updates</span>
              </div>
            </div>
            <p className="text-2xl font-bold text-gray-900">
              {dashboardData.recent_price_changes?.length || 0}
            </p>
            <p className="text-sm text-gray-500 mt-1">Last 24 hours</p>
          </div>
        </div>
      )}

      {/* Pricing Analytics */}
      {pricingData && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Price Changes Over Time */}
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Price Changes Over Time</h3>
            {pricingData.pricing_changes?.length > 0 ? (
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={pricingData.pricing_changes}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="date" />
                  <YAxis />
                  <Tooltip />
                  <Line 
                    type="monotone" 
                    dataKey="price_changes" 
                    stroke="#3b82f6" 
                    strokeWidth={2}
                  />
                </LineChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-center py-8 text-gray-500">
                No pricing data available for this timeframe
              </div>
            )}
          </div>

          {/* Pricing by Category */}
          <div className="bg-white p-6 rounded-lg shadow-soft">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Pricing by Category</h3>
            {pricingData.pricing_distribution?.length > 0 ? (
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={pricingData.pricing_distribution}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="category" />
                  <YAxis />
                  <Tooltip />
                  <Bar dataKey="avg_price" fill="#3b82f6" />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-center py-8 text-gray-500">
                No category data available
              </div>
            )}
          </div>
        </div>
      )}

      {/* Order Analytics */}
      {orderData && (
        <div className="bg-white p-6 rounded-lg shadow-soft">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Order Analytics</h3>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-6">
            <div className="text-center">
              <p className="text-2xl font-bold text-gray-900">{orderData.total_orders || 0}</p>
              <p className="text-sm text-gray-600">Total Orders</p>
            </div>
            <div className="text-center">
              <p className="text-2xl font-bold text-gray-900">{formatPrice(orderData.total_revenue || 0)}</p>
              <p className="text-sm text-gray-600">Total Revenue</p>
            </div>
            <div className="text-center">
              <p className="text-2xl font-bold text-gray-900">{formatPrice(orderData.avg_order_value || 0)}</p>
              <p className="text-sm text-gray-600">Avg Order Value</p>
            </div>
            <div className="text-center">
              <p className="text-2xl font-bold text-gray-900">{orderData.unique_customers || 0}</p>
              <p className="text-sm text-gray-600">Unique Customers</p>
            </div>
          </div>

          {/* Top Products */}
          {orderData.top_products?.length > 0 && (
            <div>
              <h4 className="text-md font-semibold text-gray-900 mb-4">Top Selling Products</h4>
              <div className="space-y-3">
                {orderData.top_products.slice(0, 5).map((product, index) => (
                  <div key={product.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center space-x-3">
                      <span className="flex items-center justify-center w-8 h-8 bg-primary-100 text-primary-600 rounded-full text-sm font-medium">
                        {index + 1}
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{product.name}</p>
                        <p className="text-sm text-gray-500">{product.total_sold} sold</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="font-medium text-gray-900">{formatPrice(product.total_revenue)}</p>
                      <p className="text-sm text-gray-500">Revenue</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Competitor Price Analysis */}
      {competitorData.length > 0 && (
        <div className="bg-white p-6 rounded-lg shadow-soft">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Competitor Price Analysis</h3>
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Product
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Our Price
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Avg Competitor
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Price Difference
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Competitors
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {competitorData.slice(0, 10).map((product) => (
                  <tr key={product.id}>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">{product.name}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{formatPrice(product.current_price)}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{formatPrice(product.avg_competitor_price)}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className={`flex items-center text-sm font-medium ${
                        product.price_difference_percentage < 0 ? 'text-success-600' : 'text-danger-600'
                      }`}>
                        {product.price_difference_percentage < 0 ? (
                          <ArrowDown className="h-4 w-4 mr-1" />
                        ) : (
                          <ArrowUp className="h-4 w-4 mr-1" />
                        )}
                        {Math.abs(product.price_difference_percentage).toFixed(1)}%
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm text-gray-900">{product.competitor_count}</div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Top Price Changes */}
      {pricingData?.top_price_changes?.length > 0 && (
        <div className="bg-white p-6 rounded-lg shadow-soft">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Products with Highest Price Changes</h3>
          <div className="space-y-3">
            {pricingData.top_price_changes.slice(0, 5).map((product) => (
              <div key={product.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                <div>
                  <p className="font-medium text-gray-900">{product.name}</p>
                  <p className="text-sm text-gray-500">
                    {formatPrice(product.base_price)} → {formatPrice(product.current_price)}
                  </p>
                </div>
                <div className="text-right">
                  <div className={`flex items-center text-sm font-medium ${
                    product.price_change_percentage > 0 ? 'text-success-600' : 'text-danger-600'
                  }`}>
                    {product.price_change_percentage > 0 ? (
                      <ArrowUp className="h-4 w-4 mr-1" />
                    ) : (
                      <ArrowDown className="h-4 w-4 mr-1" />
                    )}
                    {Math.abs(product.price_change_percentage).toFixed(1)}%
                  </div>
                  <p className="text-xs text-gray-500">
                    {product.total_price_changes} changes total
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Analytics;
